58	/// Checks the result of a vkXXXXXX call and throws an error on failure
59	#define VK_CHECK_THROW(x)                                                       \
60		do {                                                                        \
61			VkResult result = x;                                                    \
62			if (result != VK_SUCCESS)                                               \
63				throw std::runtime_error(std::string(FILE_LINE " " #x " failed"));  \
64		} while(0)
65	
66	std::string ngx_error_string(NVSDK_NGX_Result result) {
67		std::wstring wstr = GetNGXResultAsString(result);
68		std::wstring_convert<std::codecvt_utf8<wchar_t>, wchar_t> converter;
69		return converter.to_bytes(wstr);
70	};
71	
72	/// Checks the result of a NVSDK_NGX_XXXXXX call and throws an error on failure
73	#define NGX_CHECK_THROW(x)                                                                                            \
74		do {                                                                                                              \
75			NVSDK_NGX_Result result = x;                                                                                  \
76			if (NVSDK_NGX_FAILED(result))                                                                                 \
77				throw std::runtime_error(std::string(FILE_LINE " " #x " failed with error ") + ngx_error_string(result)); \
78		} while(0)
79	
80	static VKAPI_ATTR VkBool32 VKAPI_CALL vk_debug_callback(
81		VkDebugUtilsMessageSeverityFlagBitsEXT message_severity,
82		VkDebugUtilsMessageTypeFlagsEXT message_type,
83		const VkDebugUtilsMessengerCallbackDataEXT* callback_data,
84		void* user_data
85	) {
86		// Ignore json files that couldn't be found... third party tools sometimes install bogus layers
87		// that manifest as warnings like this.
88		if (std::string{callback_data->pMessage}.find("Failed to open JSON file") != std::string::npos) {
89			return VK_FALSE;
90		}
91	
92		if (message_severity & VK_DEBUG_UTILS_MESSAGE_SEVERITY_ERROR_BIT_EXT) {
93			tlog::warning() << "Vulkan error: " << callback_data->pMessage;
94		} else if (message_severity & VK_DEBUG_UTILS_MESSAGE_SEVERITY_WARNING_BIT_EXT) {
95			tlog::warning() << "Vulkan: " << callback_data->pMessage;
96		} else {
97			tlog::info() << "Vulkan: " << callback_data->pMessage;
98		}
99	
100		return VK_FALSE;
101	}
