159	class VulkanAndNgx : public IDlssProvider, public std::enable_shared_from_this<VulkanAndNgx> {
160	public:
161		VulkanAndNgx() {
162			ScopeGuard cleanup_guard{[&]() { clear(); }};
163	
164			if (!glfwVulkanSupported()) {
165				throw std::runtime_error{"!glfwVulkanSupported()"};
166			}
167	
168			// -------------------------------
169			// Vulkan Instance
170			// -------------------------------
171			VkApplicationInfo app_info{};
172			app_info.sType = VK_STRUCTURE_TYPE_APPLICATION_INFO;
173			app_info.pApplicationName = "NGP";
174			app_info.applicationVersion = VK_MAKE_VERSION(1, 0, 0);
175			app_info.pEngineName = "No engine";
176			app_info.engineVersion = VK_MAKE_VERSION(1, 0, 0);
177			app_info.apiVersion = VK_API_VERSION_1_0;
178	
179			VkInstanceCreateInfo instance_create_info = {};
180			instance_create_info.sType = VK_STRUCTURE_TYPE_INSTANCE_CREATE_INFO;
181			instance_create_info.pApplicationInfo = &app_info;
182	
183			std::vector<const char*> instance_extensions;
184			std::vector<const char*> device_extensions;
185	
186			uint32_t n_ngx_instance_extensions = 0;
187			const char** ngx_instance_extensions;
188	
189			uint32_t n_ngx_device_extensions = 0;
190			const char** ngx_device_extensions;
191	
192			NVSDK_NGX_VULKAN_RequiredExtensions(&n_ngx_instance_extensions, &ngx_instance_extensions, &n_ngx_device_extensions, &ngx_device_extensions);
193	
194			for (uint32_t i = 0; i < n_ngx_instance_extensions; ++i) {
195				instance_extensions.emplace_back(ngx_instance_extensions[i]);
196			}
197	
198			instance_extensions.emplace_back(VK_KHR_DEVICE_GROUP_CREATION_EXTENSION_NAME);
199			instance_extensions.emplace_back(VK_KHR_EXTERNAL_FENCE_CAPABILITIES_EXTENSION_NAME);
200			instance_extensions.emplace_back(VK_KHR_EXTERNAL_MEMORY_CAPABILITIES_EXTENSION_NAME);
201			instance_extensions.emplace_back(VK_KHR_GET_PHYSICAL_DEVICE_PROPERTIES_2_EXTENSION_NAME);
202	
203			auto supported_instance_layers = vk_supported_instance_layers();
204	
205			const char* validation_layer_name = "VK_LAYER_KHRONOS_validation";
206			bool instance_validation_layer_enabled = supported_instance_layers.count(validation_layer_name) > 0;
207			if (!instance_validation_layer_enabled) {
208				tlog::warning() << "Vulkan instance validation layer is not available. Vulkan errors will be difficult to diagnose.";
209			}
210	
211			std::vector<const char*> instance_layers;
212			if (instance_validation_layer_enabled) {
213				instance_layers.emplace_back(validation_layer_name);
214			}
215	
216			instance_create_info.enabledLayerCount = static_cast<uint32_t>(instance_layers.size());
217			instance_create_info.ppEnabledLayerNames = instance_layers.empty() ? nullptr : instance_layers.data();
218	
219			if (instance_validation_layer_enabled) {
220				instance_extensions.emplace_back(VK_EXT_DEBUG_UTILS_EXTENSION_NAME);
221			}
222	
223			auto supported_instance_extensions = vk_supported_instance_extensions(nullptr);
224			for (const auto& e : instance_extensions) {
225				if (supported_instance_extensions.count(e) == 0) {
226					throw std::runtime_error{fmt::format("Required instance extension '{}' is not supported.", e)};
227				}
228			}
229	
230			instance_create_info.enabledExtensionCount = (uint32_t)instance_extensions.size();
231			instance_create_info.ppEnabledExtensionNames = instance_extensions.data();
232	
233			VkDebugUtilsMessengerCreateInfoEXT debug_messenger_create_info = {};
234			debug_messenger_create_info.sType = VK_STRUCTURE_TYPE_DEBUG_UTILS_MESSENGER_CREATE_INFO_EXT;
235			debug_messenger_create_info.messageSeverity = VK_DEBUG_UTILS_MESSAGE_SEVERITY_WARNING_BIT_EXT | VK_DEBUG_UTILS_MESSAGE_SEVERITY_ERROR_BIT_EXT;
236			debug_messenger_create_info.messageType = VK_DEBUG_UTILS_MESSAGE_TYPE_GENERAL_BIT_EXT | VK_DEBUG_UTILS_MESSAGE_TYPE_VALIDATION_BIT_EXT | VK_DEBUG_UTILS_MESSAGE_TYPE_PERFORMANCE_BIT_EXT;
237			debug_messenger_create_info.pfnUserCallback = vk_debug_callback;
238			debug_messenger_create_info.pUserData = nullptr;
239	
240			if (instance_validation_layer_enabled) {
241				instance_create_info.pNext = &debug_messenger_create_info;
242			}
243	
244			VK_CHECK_THROW(vkCreateInstance(&instance_create_info, nullptr, &m_vk_instance));
245	
246			if (instance_validation_layer_enabled) {
247				auto CreateDebugUtilsMessengerEXT = [](VkInstance instance, const VkDebugUtilsMessengerCreateInfoEXT* pCreateInfo, const VkAllocationCallbacks* pAllocator, VkDebugUtilsMessengerEXT* pDebugMessenger) {
248					auto func = (PFN_vkCreateDebugUtilsMessengerEXT)vkGetInstanceProcAddr(instance, "vkCreateDebugUtilsMessengerEXT");
249					if (func != nullptr) {
250						return func(instance, pCreateInfo, pAllocator, pDebugMessenger);
251					} else {
252						return VK_ERROR_EXTENSION_NOT_PRESENT;
253					}
254				};
255	
256				if (CreateDebugUtilsMessengerEXT(m_vk_instance, &debug_messenger_create_info, nullptr, &m_vk_debug_messenger) != VK_SUCCESS) {
257					tlog::warning() << "Vulkan: could not initialize debug messenger.";
258				}
259			}
260	
261			// -------------------------------
262			// Vulkan Physical Device
263			// -------------------------------
264			uint32_t n_devices = 0;
265			vkEnumeratePhysicalDevices(m_vk_instance, &n_devices, nullptr);
266	
267			if (n_devices == 0) {
268				throw std::runtime_error{"Failed to find GPUs with Vulkan support."};
269			}
270	
271			std::vector<VkPhysicalDevice> devices(n_devices);
272			vkEnumeratePhysicalDevices(m_vk_instance, &n_devices, devices.data());
273	
274			struct QueueFamilyIndices {
275				int graphics_family = -1;
276				int compute_family = -1;
277				int transfer_family = -1;
278				int all_family = -1;
279			};
280	
281			auto find_queue_families = [](VkPhysicalDevice device) {
282				QueueFamilyIndices indices;
283	
284				uint32_t queue_family_count = 0;
285				vkGetPhysicalDeviceQueueFamilyProperties(device, &queue_family_count, nullptr);
286	
287				std::vector<VkQueueFamilyProperties> queue_families(queue_family_count);
288				vkGetPhysicalDeviceQueueFamilyProperties(device, &queue_family_count, queue_families.data());
289	
290				int i = 0;
291				for (const auto& queue_family : queue_families) {
292					if (queue_family.queueFlags & VK_QUEUE_GRAPHICS_BIT) {
293						indices.graphics_family = i;
294					}
295	
296					if (queue_family.queueFlags & VK_QUEUE_COMPUTE_BIT) {
297						indices.compute_family = i;
298					}
299	
300					if (queue_family.queueFlags & VK_QUEUE_TRANSFER_BIT) {
301						indices.transfer_family = i;
302					}
303	
304					if ((queue_family.queueFlags & VK_QUEUE_GRAPHICS_BIT) && (queue_family.queueFlags & VK_QUEUE_COMPUTE_BIT) && (queue_family.queueFlags & VK_QUEUE_TRANSFER_BIT)) {
305						indices.all_family = i;
306					}
307	
308					i++;
309				}
310	
311				return indices;
312			};
313	
314			cudaDeviceProp cuda_device_prop;
315			CUDA_CHECK_THROW(cudaGetDeviceProperties(&cuda_device_prop, cuda_device()));
316	
317			auto is_same_as_cuda_device = [&](VkPhysicalDevice device) {
318				VkPhysicalDeviceIDProperties physical_device_id_properties = {};
319				physical_device_id_properties.sType = VK_STRUCTURE_TYPE_PHYSICAL_DEVICE_ID_PROPERTIES;
320				physical_device_id_properties.pNext = NULL;
321	
322				VkPhysicalDeviceProperties2 physical_device_properties = {};
323				physical_device_properties.sType = VK_STRUCTURE_TYPE_PHYSICAL_DEVICE_PROPERTIES_2;
324				physical_device_properties.pNext = &physical_device_id_properties;
325	
326				vkGetPhysicalDeviceProperties2(device, &physical_device_properties);
327	
328				return !memcmp(&cuda_device_prop.uuid, physical_device_id_properties.deviceUUID, VK_UUID_SIZE) && find_queue_families(device).all_family >= 0;
329			};
330	
331			uint32_t device_id = 0;
332			for (uint32_t i = 0; i < n_devices; ++i) {
333				if (is_same_as_cuda_device(devices[i])) {
334					m_vk_physical_device = devices[i];
335					device_id = i;
336					break;
337				}
338			}
339	
340			if (m_vk_physical_device == VK_NULL_HANDLE) {
341				throw std::runtime_error{"Failed to find Vulkan device corresponding to CUDA device."};
342			}
343	
344			for (uint32_t i = 0; i < n_ngx_device_extensions; ++i) {
345				device_extensions.emplace_back(ngx_device_extensions[i]);
346			}
347	
348			device_extensions.emplace_back(VK_KHR_EXTERNAL_MEMORY_EXTENSION_NAME);
349	#ifdef _WIN32
350			device_extensions.emplace_back(VK_KHR_EXTERNAL_MEMORY_WIN32_EXTENSION_NAME);
351	#else
352			device_extensions.emplace_back(VK_KHR_EXTERNAL_MEMORY_FD_EXTENSION_NAME);
353	#endif
354			device_extensions.emplace_back(VK_KHR_DEVICE_GROUP_EXTENSION_NAME);
355	
356			auto supported_device_extensions = vk_supported_device_extensions(m_vk_physical_device, nullptr);
357			for (const auto& e : device_extensions) {
358				if (supported_device_extensions.count(e) == 0) {
359					throw std::runtime_error{fmt::format("Required device extension '{}' is not supported.", e)};
360				}
361			}
362	
363			// -------------------------------
364			// Vulkan Logical Device
365			// -------------------------------
366			VkPhysicalDeviceProperties physical_device_properties;
367			vkGetPhysicalDeviceProperties(m_vk_physical_device, &physical_device_properties);
368	
369			QueueFamilyIndices indices = find_queue_families(m_vk_physical_device);
370	
371			VkDeviceQueueCreateInfo queue_create_info{};
372			queue_create_info.sType = VK_STRUCTURE_TYPE_DEVICE_QUEUE_CREATE_INFO;
373			queue_create_info.queueFamilyIndex = indices.all_family;
374			queue_create_info.queueCount = 1;
375	
376			float queue_priority = 1.0f;
377			queue_create_info.pQueuePriorities = &queue_priority;
378	
379			VkPhysicalDeviceFeatures device_features = {};
380			device_features.shaderStorageImageWriteWithoutFormat = true;
381	
382			VkDeviceCreateInfo device_create_info = {};
383			device_create_info.sType = VK_STRUCTURE_TYPE_DEVICE_CREATE_INFO;
384			device_create_info.pQueueCreateInfos = &queue_create_info;
385			device_create_info.queueCreateInfoCount = 1;
386			device_create_info.pEnabledFeatures = &device_features;
387			device_create_info.enabledExtensionCount = (uint32_t)device_extensions.size();
388			device_create_info.ppEnabledExtensionNames = device_extensions.data();
389	
390	#ifdef VK_EXT_BUFFER_DEVICE_ADDRESS_EXTENSION_NAME
391			VkPhysicalDeviceBufferDeviceAddressFeaturesEXT buffer_device_address_feature = {};
392			buffer_device_address_feature.sType = VK_STRUCTURE_TYPE_PHYSICAL_DEVICE_BUFFER_DEVICE_ADDRESS_FEATURES_EXT;
393			buffer_device_address_feature.bufferDeviceAddress = VK_TRUE;
394			device_create_info.pNext = &buffer_device_address_feature;
395	#else
396			throw std::runtime_error{"Buffer device address extension not available."};
397	#endif
398	
399			VK_CHECK_THROW(vkCreateDevice(m_vk_physical_device, &device_create_info, nullptr, &m_vk_device));
400	
401			// -----------------------------------------------
402			// Vulkan queue / command pool / command buffer
403			// -----------------------------------------------
404			vkGetDeviceQueue(m_vk_device, indices.all_family, 0, &m_vk_queue);
405	
406			VkCommandPoolCreateInfo command_pool_info = {};
407			command_pool_info.sType = VK_STRUCTURE_TYPE_COMMAND_POOL_CREATE_INFO;
408			command_pool_info.flags = VK_COMMAND_POOL_CREATE_RESET_COMMAND_BUFFER_BIT;
409			command_pool_info.queueFamilyIndex = indices.all_family;
410	
411			VK_CHECK_THROW(vkCreateCommandPool(m_vk_device, &command_pool_info, nullptr, &m_vk_command_pool));
412	
413			VkCommandBufferAllocateInfo command_buffer_alloc_info = {};
414			command_buffer_alloc_info.sType = VK_STRUCTURE_TYPE_COMMAND_BUFFER_ALLOCATE_INFO;
415			command_buffer_alloc_info.commandPool = m_vk_command_pool;
416			command_buffer_alloc_info.level = VK_COMMAND_BUFFER_LEVEL_PRIMARY;
417			command_buffer_alloc_info.commandBufferCount = 1;
418	
419			VK_CHECK_THROW(vkAllocateCommandBuffers(m_vk_device, &command_buffer_alloc_info, &m_vk_command_buffer));
420	
421			// -------------------------------
422			// NGX init
423			// -------------------------------
424			std::wstring path;
425	#ifdef _WIN32
426			path = fs::path::getcwd().wstr();
427	#else
428			std::string tmp = fs::path::getcwd().str();
429			std::wstring_convert<std::codecvt_utf8<wchar_t>, wchar_t> converter;
430			path = converter.from_bytes(tmp);
431	#endif
432	
433			NGX_CHECK_THROW(NVSDK_NGX_VULKAN_Init_with_ProjectID("ea75345e-5a42-4037-a5c9-59bf94dee157", NVSDK_NGX_ENGINE_TYPE_CUSTOM, "1.0.0", path.c_str(), m_vk_instance, m_vk_physical_device, m_vk_device));
434			m_ngx_initialized = true;
435	
436			// -------------------------------
437			// Ensure DLSS capability
438			// -------------------------------
439			NGX_CHECK_THROW(NVSDK_NGX_VULKAN_GetCapabilityParameters(&m_ngx_parameters));
440	
441			int needs_updated_driver = 0;
442			unsigned int min_driver_version_major = 0;
443			unsigned int min_driver_version_minor = 0;
444			NVSDK_NGX_Result result_updated_driver = m_ngx_parameters->Get(NVSDK_NGX_Parameter_SuperSampling_NeedsUpdatedDriver, &needs_updated_driver);
445			NVSDK_NGX_Result result_min_driver_version_major = m_ngx_parameters->Get(NVSDK_NGX_Parameter_SuperSampling_MinDriverVersionMajor, &min_driver_version_major);
446			NVSDK_NGX_Result result_min_driver_version_minor = m_ngx_parameters->Get(NVSDK_NGX_Parameter_SuperSampling_MinDriverVersionMinor, &min_driver_version_minor);
447			if (result_updated_driver == NVSDK_NGX_Result_Success && result_min_driver_version_major == NVSDK_NGX_Result_Success && result_min_driver_version_minor == NVSDK_NGX_Result_Success) {
448				if (needs_updated_driver) {
449					throw std::runtime_error{fmt::format("Driver too old. Minimum version required is {}.{}", min_driver_version_major, min_driver_version_minor)};
450				}
451			}
452	
453			int dlss_available  = 0;
454			NVSDK_NGX_Result ngx_result = m_ngx_parameters->Get(NVSDK_NGX_Parameter_SuperSampling_Available, &dlss_available);
455			if (ngx_result != NVSDK_NGX_Result_Success || !dlss_available) {
456				ngx_result = NVSDK_NGX_Result_Fail;
457				NVSDK_NGX_Parameter_GetI(m_ngx_parameters, NVSDK_NGX_Parameter_SuperSampling_FeatureInitResult, (int*)&ngx_result);
458				throw std::runtime_error{fmt::format("DLSS not available: {}", ngx_error_string(ngx_result))};
459			}
460	
461			cleanup_guard.disarm();
462	
463			tlog::success() << "Initialized Vulkan and NGX on GPU #" << device_id << ": " << physical_device_properties.deviceName;
464		}
