484			}
485	
486			if (m_vk_device) {
487				vkDestroyDevice(m_vk_device, nullptr);
488				m_vk_device = VK_NULL_HANDLE;
489			}
490	
491			if (m_vk_debug_messenger) {
492				auto DestroyDebugUtilsMessengerEXT = [](VkInstance instance, VkDebugUtilsMessengerEXT debugMessenger, const VkAllocationCallbacks* pAllocator) {
493					auto func = (PFN_vkDestroyDebugUtilsMessengerEXT)vkGetInstanceProcAddr(instance, "vkDestroyDebugUtilsMessengerEXT");
494					if (func != nullptr) {
495						func(instance, debugMessenger, pAllocator);
496					}
497				};
498	
499				DestroyDebugUtilsMessengerEXT(m_vk_instance, m_vk_debug_messenger, nullptr);
500				m_vk_debug_messenger = VK_NULL_HANDLE;
501			}
502	
503			if (m_vk_instance) {
504				vkDestroyInstance(m_vk_instance, nullptr);
505				m_vk_instance = VK_NULL_HANDLE;
506			}
507		}
