509		uint32_t vk_find_memory_type(uint32_t type_filter, VkMemoryPropertyFlags properties) {
510			VkPhysicalDeviceMemoryProperties mem_properties;
511			vkGetPhysicalDeviceMemoryProperties(m_vk_physical_device, &mem_properties);
512	
513			for (uint32_t i = 0; i < mem_properties.memoryTypeCount; i++) {
514				if (type_filter & (1 << i) && (mem_properties.memoryTypes[i].propertyFlags & properties) == properties) {
515					return i;
516				}
517			}
518	
519			throw std::runtime_error{"Failed to find suitable memory type."};
520		}
