602	class VulkanTexture {
603	public:
604		VulkanTexture(std::shared_ptr<VulkanAndNgx> vk, const ivec2& size, uint32_t n_channels) : m_vk{vk}, m_size{size}, m_n_channels{n_channels} {
605			ScopeGuard cleanup_guard{[&]() { clear(); }};
606	
607			VkImageCreateInfo image_info{};
608			image_info.sType = VK_STRUCTURE_TYPE_IMAGE_CREATE_INFO;
609			image_info.imageType = VK_IMAGE_TYPE_2D;
610			image_info.extent.width = static_cast<uint32_t>(m_size.x);
611			image_info.extent.height = static_cast<uint32_t>(m_size.y);
612			image_info.extent.depth = 1;
613			image_info.mipLevels = 1;
614			image_info.arrayLayers = 1;
615	
616			switch (n_channels) {
617				case 1: image_info.format = VK_FORMAT_R32_SFLOAT; break;
618				case 2: image_info.format = VK_FORMAT_R32G32_SFLOAT; break;
619				case 3: image_info.format = VK_FORMAT_R32G32B32_SFLOAT; break;
620				case 4: image_info.format = VK_FORMAT_R32G32B32A32_SFLOAT; break;
621				default: throw std::runtime_error{"VulkanTexture only supports 1, 2, 3, or 4 channels."};
622			}
623	
624			image_info.tiling = VK_IMAGE_TILING_OPTIMAL;
625			image_info.initialLayout = VK_IMAGE_LAYOUT_UNDEFINED;
626			image_info.usage = VK_IMAGE_USAGE_TRANSFER_DST_BIT | VK_IMAGE_USAGE_SAMPLED_BIT | VK_IMAGE_USAGE_STORAGE_BIT;
627			image_info.sharingMode = VK_SHARING_MODE_EXCLUSIVE;
628			image_info.samples = VK_SAMPLE_COUNT_1_BIT;
629			image_info.flags = 0;
630	
631			VkExternalMemoryImageCreateInfoKHR ext_image_info = {};
632			ext_image_info.sType = VK_STRUCTURE_TYPE_EXTERNAL_MEMORY_IMAGE_CREATE_INFO_KHR;
633	
634	#ifdef _WIN32
635			ext_image_info.handleTypes |= VK_EXTERNAL_MEMORY_HANDLE_TYPE_OPAQUE_WIN32_BIT_KHR;
636	#else
637			ext_image_info.handleTypes |= VK_EXTERNAL_MEMORY_HANDLE_TYPE_OPAQUE_FD_BIT_KHR;
638	#endif
639	
640			image_info.pNext = &ext_image_info;
641	
642			VK_CHECK_THROW(vkCreateImage(m_vk->vk_device(), &image_info, nullptr, &m_vk_image));
643	
644			// Create device memory to back up the image
645			VkMemoryRequirements mem_requirements = {};
646	
647			vkGetImageMemoryRequirements(m_vk->vk_device(), m_vk_image, &mem_requirements);
648	
649			VkMemoryAllocateInfo mem_alloc_info = {};
650			mem_alloc_info.sType = VK_STRUCTURE_TYPE_MEMORY_ALLOCATE_INFO;
651			mem_alloc_info.allocationSize = mem_requirements.size;
652			mem_alloc_info.memoryTypeIndex = m_vk->vk_find_memory_type(mem_requirements.memoryTypeBits, VK_MEMORY_PROPERTY_DEVICE_LOCAL_BIT);
653	
654			VkExportMemoryAllocateInfoKHR export_info = {};
655			export_info.sType = VK_STRUCTURE_TYPE_EXPORT_MEMORY_ALLOCATE_INFO_KHR;
656			export_info.handleTypes = ext_image_info.handleTypes;
657	
658			mem_alloc_info.pNext = &export_info;
659	
660			VK_CHECK_THROW(vkAllocateMemory(m_vk->vk_device(), &mem_alloc_info, nullptr, &m_vk_device_memory));
661			VK_CHECK_THROW(vkBindImageMemory(m_vk->vk_device(), m_vk_image, m_vk_device_memory, 0));
662	
663			m_vk->vk_command_buffer_begin();
664	
665			VkImageMemoryBarrier barrier = {};
666			barrier.sType = VK_STRUCTURE_TYPE_IMAGE_MEMORY_BARRIER;
667			barrier.oldLayout = VK_IMAGE_LAYOUT_UNDEFINED;
668			barrier.newLayout = VK_IMAGE_LAYOUT_GENERAL;
669			barrier.srcQueueFamilyIndex = VK_QUEUE_FAMILY_IGNORED;
670			barrier.dstQueueFamilyIndex = VK_QUEUE_FAMILY_IGNORED;
671			barrier.image = m_vk_image;
672			barrier.subresourceRange.aspectMask = VK_IMAGE_ASPECT_COLOR_BIT;
673			barrier.subresourceRange.baseMipLevel = 0;
674			barrier.subresourceRange.levelCount = 1;
675			barrier.subresourceRange.baseArrayLayer = 0;
676			barrier.subresourceRange.layerCount = 1;
677			barrier.srcAccessMask = 0;
678			barrier.dstAccessMask = VK_ACCESS_MEMORY_READ_BIT | VK_ACCESS_MEMORY_WRITE_BIT | VK_ACCESS_SHADER_READ_BIT | VK_ACCESS_SHADER_WRITE_BIT | VK_ACCESS_COLOR_ATTACHMENT_READ_BIT | VK_ACCESS_COLOR_ATTACHMENT_WRITE_BIT;
679	
680			vkCmdPipelineBarrier(
681				m_vk->vk_command_buffer(),
682				VK_PIPELINE_STAGE_TOP_OF_PIPE_BIT, VK_PIPELINE_STAGE_ALL_COMMANDS_BIT,
683				0,
684				0, nullptr,
685				0, nullptr,
686				1, &barrier
687			);
688	
689			m_vk->vk_command_buffer_end_and_submit_sync();
690	
691			// Image view
692			VkImageViewCreateInfo view_info = {};
693			view_info.sType = VK_STRUCTURE_TYPE_IMAGE_VIEW_CREATE_INFO;
694			view_info.image = m_vk_image;
695			view_info.viewType = VK_IMAGE_VIEW_TYPE_2D;
696			view_info.format = image_info.format;
697			view_info.subresourceRange = barrier.subresourceRange;
698	
699			VK_CHECK_THROW(vkCreateImageView(m_vk->vk_device(), &view_info, nullptr, &m_vk_image_view));
700	
701			// Map to NGX
702			m_ngx_resource = NVSDK_NGX_Create_ImageView_Resource_VK(m_vk_image_view, m_vk_image, view_info.subresourceRange, image_info.format, m_size.x, m_size.y, true);
703	
704			// Map to CUDA memory: VkDeviceMemory->FD/HANDLE->cudaExternalMemory->CUDA pointer
705	#ifdef _WIN32
706			HANDLE handle = nullptr;
707			VkMemoryGetWin32HandleInfoKHR handle_info = {};
708			handle_info.sType = VK_STRUCTURE_TYPE_MEMORY_GET_WIN32_HANDLE_INFO_KHR;
709			handle_info.memory = m_vk_device_memory;
710			handle_info.handleType = VK_EXTERNAL_MEMORY_HANDLE_TYPE_OPAQUE_WIN32_BIT;
711			auto pfn_vkGetMemory = (PFN_vkGetMemoryWin32HandleKHR)vkGetDeviceProcAddr(m_vk->vk_device(), "vkGetMemoryWin32HandleKHR");
712	#else
713			int handle = -1;
714			VkMemoryGetFdInfoKHR handle_info = {};
715			handle_info.sType = VK_STRUCTURE_TYPE_MEMORY_GET_FD_INFO_KHR;
716			handle_info.memory = m_vk_device_memory;
717			handle_info.handleType = VK_EXTERNAL_MEMORY_HANDLE_TYPE_OPAQUE_FD_BIT_KHR;
718			auto pfn_vkGetMemory = (PFN_vkGetMemoryFdKHR)vkGetDeviceProcAddr(m_vk->vk_device(), "vkGetMemoryFdKHR");
719	#endif
720	
721			if (!pfn_vkGetMemory) {
722				throw std::runtime_error{"Failed to locate pfn_vkGetMemory."};
723			}
724	
725			VK_CHECK_THROW(pfn_vkGetMemory(m_vk->vk_device(), &handle_info, &handle));
726	
727			// Map handle to CUDA memory
728			cudaExternalMemoryHandleDesc external_memory_handle_desc = {};
729			memset(&external_memory_handle_desc, 0, sizeof(external_memory_handle_desc));
730	
731	#ifdef _WIN32
732			external_memory_handle_desc.type = cudaExternalMemoryHandleTypeOpaqueWin32;
733			external_memory_handle_desc.handle.win32.handle = handle;
734	#else
735			external_memory_handle_desc.type = cudaExternalMemoryHandleTypeOpaqueFd;
736			external_memory_handle_desc.handle.fd = handle;
737	#endif
738			external_memory_handle_desc.size = mem_requirements.size;
739	
740			CUDA_CHECK_THROW(cudaImportExternalMemory(&m_cuda_external_memory, &external_memory_handle_desc));
741	
742			cudaExternalMemoryBufferDesc external_memory_buffer_desc = {};
743			memset(&external_memory_buffer_desc, 0, sizeof(external_memory_buffer_desc));
744			external_memory_buffer_desc.offset = 0;
745			external_memory_buffer_desc.size = mem_requirements.size;
746	
747			void* ptr;
748			CUDA_CHECK_THROW(cudaExternalMemoryGetMappedBuffer(&ptr, m_cuda_external_memory, &external_memory_buffer_desc));
749			m_cuda_data = (float*)ptr;
750	
751			// ----------------
752			// Also get a surface object array, as the above buffer might be too cumbersome to deal with
753			// ----------------
754			cudaExternalMemoryMipmappedArrayDesc external_memory_mipmapped_array_desc = {};
755			memset(&external_memory_mipmapped_array_desc, 0, sizeof(external_memory_mipmapped_array_desc));
756	
757			cudaChannelFormatDesc channel_format = {};
758			channel_format.f = cudaChannelFormatKindFloat;
759			switch (n_channels) {
760				case 1: channel_format.x = 32; channel_format.y = 0;  channel_format.z = 0;  channel_format.w = 0;  break;
761				case 2: channel_format.x = 32; channel_format.y = 32; channel_format.z = 0;  channel_format.w = 0;  break;
762				case 3: channel_format.x = 32; channel_format.y = 32; channel_format.z = 32; channel_format.w = 0;  break;
763				case 4: channel_format.x = 32; channel_format.y = 32; channel_format.z = 32; channel_format.w = 32; break;
764				default: throw std::runtime_error{"VulkanTexture only supports 1, 2, 3, or 4 channels."};
765			}
766	
767			cudaExtent extent = {};
768			extent.width = m_size.x;
769			extent.height = m_size.y;
770			extent.depth = 0;
771	
772			external_memory_mipmapped_array_desc.offset = 0;
773			external_memory_mipmapped_array_desc.formatDesc = channel_format;
774			external_memory_mipmapped_array_desc.extent = extent;
775			external_memory_mipmapped_array_desc.flags = cudaArraySurfaceLoadStore;
776			external_memory_mipmapped_array_desc.numLevels = 1;
777	
778			cudaExternalMemoryGetMappedMipmappedArray(&m_cuda_mipmapped_array, m_cuda_external_memory, &external_memory_mipmapped_array_desc);
779	
780			cudaArray_t first_level_array;
781			CUDA_CHECK_THROW(cudaGetMipmappedArrayLevel(&first_level_array, m_cuda_mipmapped_array, 0));
782	
783			struct cudaResourceDesc resource_desc;
784			memset(&resource_desc, 0, sizeof(resource_desc));
785			resource_desc.resType = cudaResourceTypeArray;
786			resource_desc.res.array.array = first_level_array;
787	
788			CUDA_CHECK_THROW(cudaCreateSurfaceObject(&m_cuda_surface_object, &resource_desc));
789	
790			m_n_bytes = mem_requirements.size;
791			g_total_n_bytes_allocated += m_n_bytes;
792	
793			cleanup_guard.disarm();
794		}
