800		void clear() {
801			g_total_n_bytes_allocated -= m_n_bytes;
802	
803			if (m_cuda_data) {
804				cudaFree(m_cuda_data);
805				m_cuda_data = nullptr;
806			}
807	
808			if (m_cuda_surface_object) {
809				cudaDestroySurfaceObject(m_cuda_surface_object);
810				m_cuda_surface_object = {};
811			}
812	
813			if (m_cuda_mipmapped_array) {
814				cudaFreeMipmappedArray(m_cuda_mipmapped_array);
815				m_cuda_mipmapped_array = {};
816			}
817	
818			if (m_cuda_external_memory) {
819				cudaDestroyExternalMemory(m_cuda_external_memory);
820				m_cuda_external_memory = {};
821			}
822	
823			if (m_vk_image_view) {
824				vkDestroyImageView(m_vk->vk_device(), m_vk_image_view, nullptr);
825				m_vk_image_view = {};
826			}
827	
828			if (m_vk_image) {
829				vkDestroyImage(m_vk->vk_device(), m_vk_image, nullptr);
830				m_vk_image = {};
831			}
832	
833			if (m_vk_device_memory) {
834				vkFreeMemory(m_vk->vk_device(), m_vk_device_memory, nullptr);
835				m_vk_device_memory = {};
836			}
837		}
