879	NVSDK_NGX_PerfQuality_Value ngx_dlss_quality(EDlssQuality quality) {
880		switch (quality) {
881			case EDlssQuality::UltraPerformance: return NVSDK_NGX_PerfQuality_Value_UltraPerformance;
882			case EDlssQuality::MaxPerformance: return NVSDK_NGX_PerfQuality_Value_MaxPerf;
883			case EDlssQuality::Balanced: return NVSDK_NGX_PerfQuality_Value_Balanced;
884			case EDlssQuality::MaxQuality: return NVSDK_NGX_PerfQuality_Value_MaxQuality;
885			case EDlssQuality::UltraQuality: return NVSDK_NGX_PerfQuality_Value_UltraQuality;
886			default: throw std::runtime_error{"Unknown DLSS quality setting."};
887		}
888	}
