890	struct DlssFeatureSpecs {
891		EDlssQuality quality;
892		ivec2 out_resolution;
893		ivec2 optimal_in_resolution;
894		ivec2 min_in_resolution;
895		ivec2 max_in_resolution;
896		float optimal_sharpness;
897	
898		float distance(const ivec2& resolution) const {
899			return length(vec2(max(max(min_in_resolution - resolution, resolution - max_in_resolution), ivec2(0))));
900		}
901	
902		ivec2 clamp_resolution(const ivec2& resolution) const {
903			return clamp(resolution, min_in_resolution, max_in_resolution);
904		}
905	};
906	
907	DlssFeatureSpecs dlss_feature_specs(NVSDK_NGX_Parameter* ngx_parameters, const ivec2& out_resolution, EDlssQuality quality) {
908		DlssFeatureSpecs specs;
909		specs.quality = quality;
910		specs.out_resolution = out_resolution;
911	
912		NGX_CHECK_THROW(NGX_DLSS_GET_OPTIMAL_SETTINGS(
913			ngx_parameters,
914			specs.out_resolution.x, specs.out_resolution.y,
915			ngx_dlss_quality(quality),
916			(uint32_t*)&specs.optimal_in_resolution.x, (uint32_t*)&specs.optimal_in_resolution.y,
917			(uint32_t*)&specs.max_in_resolution.x, (uint32_t*)&specs.max_in_resolution.y,
918			(uint32_t*)&specs.min_in_resolution.x, (uint32_t*)&specs.min_in_resolution.y,
919			&specs.optimal_sharpness
920		));
921	
922		// Don't permit input resolutions larger than the output. (Just in case DLSS allows it.)
923		specs.optimal_in_resolution = min(specs.optimal_in_resolution, out_resolution);
924		specs.max_in_resolution = min(specs.max_in_resolution, out_resolution);
925		specs.min_in_resolution = min(specs.min_in_resolution, out_resolution);
926	
927		return specs;
928	}
