933			// Initialize DLSS
934			unsigned int creation_node_mask = 1;
935			unsigned int visibility_node_mask = 1;
936	
937			int dlss_create_feature_flags = NVSDK_NGX_DLSS_Feature_Flags_None;
938			dlss_create_feature_flags |= true ? NVSDK_NGX_DLSS_Feature_Flags_MVLowRes : 0;
939			dlss_create_feature_flags |= false ? NVSDK_NGX_DLSS_Feature_Flags_MVJittered : 0;
940			dlss_create_feature_flags |= is_hdr ? NVSDK_NGX_DLSS_Feature_Flags_IsHDR : 0;
941			dlss_create_feature_flags |= true ? NVSDK_NGX_DLSS_Feature_Flags_DepthInverted : 0;
942			dlss_create_feature_flags |= sharpen ? NVSDK_NGX_DLSS_Feature_Flags_DoSharpening : 0;
943			dlss_create_feature_flags |= false ? NVSDK_NGX_DLSS_Feature_Flags_AutoExposure : 0;
944	
945			NVSDK_NGX_DLSS_Create_Params dlss_create_params;
946	
947			memset(&dlss_create_params, 0, sizeof(dlss_create_params));
948	
949			dlss_create_params.Feature.InWidth = m_specs.optimal_in_resolution.x;
950			dlss_create_params.Feature.InHeight = m_specs.optimal_in_resolution.y;
951			dlss_create_params.Feature.InTargetWidth = m_specs.out_resolution.x;
952			dlss_create_params.Feature.InTargetHeight = m_specs.out_resolution.y;
953			dlss_create_params.Feature.InPerfQualityValue = ngx_dlss_quality(m_specs.quality);
954			dlss_create_params.InFeatureCreateFlags = dlss_create_feature_flags;
955	
956			{
957				m_vk_and_ngx->vk_command_buffer_begin();
958				ScopeGuard command_buffer_guard{[&]() { m_vk_and_ngx->vk_command_buffer_end_and_submit_sync(); }};
959	
960				NGX_CHECK_THROW(NGX_VULKAN_CREATE_DLSS_EXT(m_vk_and_ngx->vk_command_buffer(), creation_node_mask, visibility_node_mask, &m_ngx_dlss, m_vk_and_ngx->ngx_parameters(), &dlss_create_params));
961			}
