1048	class Dlss : public IDlss {
1049	public:
1050		Dlss(std::shared_ptr<VulkanAndNgx> vk_and_ngx, const ivec2& max_out_resolution)
1051		:
1052		m_vk_and_ngx{vk_and_ngx},
1053		m_max_out_resolution{max_out_resolution},
1054		// Allocate all buffers at output resolution and use dynamic sub-rects
1055		// to use subsets of them. This avoids re-allocations when using DLSS
1056		// with dynamically changing input resolution.
1057		m_frame_buffer{m_vk_and_ngx, max_out_resolution, 4},
1058		m_depth_buffer{m_vk_and_ngx, max_out_resolution, 1},
1059		m_mvec_buffer{m_vk_and_ngx, max_out_resolution, 2},
1060		m_exposure_buffer{m_vk_and_ngx, {1, 1}, 1},
1061		m_output_buffer{m_vk_and_ngx, max_out_resolution, 4}
1062		{
1063			// Various quality modes of DLSS
1064			for (int i = 0; i < (int)EDlssQuality::NumDlssQualitySettings; ++i) {
1065				try {
1066					auto specs = dlss_feature_specs(m_vk_and_ngx->ngx_parameters(), max_out_resolution, (EDlssQuality)i);
1067	
1068					// Only emplace the specs if the feature can be created in practice!
1069					DlssFeature{m_vk_and_ngx, specs, true, true};
1070					DlssFeature{m_vk_and_ngx, specs, true, false};
1071					DlssFeature{m_vk_and_ngx, specs, false, true};
1072					DlssFeature{m_vk_and_ngx, specs, false, false};
1073					m_dlss_specs.emplace_back(specs);
1074				} catch (...) {}
1075			}
1076	
1077			// For super insane performance requirements (more than 3x upscaling) try UltraPerformance
1078			// with reduced output resolutions for 4.5x, 6x, 9x.
1079			std::vector<ivec2> reduced_out_resolutions = {
1080				max_out_resolution / 3 * 2,
1081				max_out_resolution / 2,
1082				max_out_resolution / 3,
1083				// max_out_resolution / 4,
1084			};
1085	
1086			for (const auto& out_resolution : reduced_out_resolutions) {
1087				try {
1088					auto specs = dlss_feature_specs(m_vk_and_ngx->ngx_parameters(), out_resolution, EDlssQuality::UltraPerformance);
1089	
1090					// Only emplace the specs if the feature can be created in practice!
1091					DlssFeature{m_vk_and_ngx, specs, true, true};
1092					DlssFeature{m_vk_and_ngx, specs, true, false};
1093					DlssFeature{m_vk_and_ngx, specs, false, true};
1094					DlssFeature{m_vk_and_ngx, specs, false, false};
1095					m_dlss_specs.emplace_back(specs);
1096				} catch (...) {}
1097			}
1098		}
1099	
1100		virtual ~Dlss() {
1101			// Destroy DLSS feature prior to killing underlying buffers.
1102			m_dlss_feature = nullptr;
1103		}
1104	
1105		void update_feature(const ivec2& in_resolution, bool is_hdr, bool sharpen) override {
1106			CUDA_CHECK_THROW(cudaDeviceSynchronize());
1107	
1108			DlssFeatureSpecs specs;
1109			bool found = false;
1110			for (const auto& s : m_dlss_specs) {
1111				if (s.distance(in_resolution) == 0.0f) {
1112					specs = s;
1113					found = true;
1114				}
1115			}
1116	
1117			if (!found) {
1118				throw std::runtime_error{"Dlss::run called with invalid input resolution."};
1119			}
1120	
1121			if (!m_dlss_feature || m_dlss_feature->is_hdr() != is_hdr || m_dlss_feature->sharpen() != sharpen || m_dlss_feature->quality() != specs.quality || m_dlss_feature->out_resolution() != specs.out_resolution) {
1122				m_dlss_feature.reset(new DlssFeature{m_vk_and_ngx, specs.out_resolution, is_hdr, sharpen, specs.quality});
1123			}
1124		}
1125	
1126		void run(
1127			const ivec2& in_resolution,
1128			bool is_hdr,
1129			float sharpening,
1130			const vec2& jitter_offset,
1131			bool shall_reset
1132		) override {
1133			CUDA_CHECK_THROW(cudaDeviceSynchronize());
1134	
1135			update_feature(in_resolution, is_hdr, sharpening != 0.0f);
1136	
1137			m_dlss_feature->run(
1138				in_resolution,
1139				jitter_offset,
1140				sharpening,
1141				shall_reset,
1142				m_frame_buffer.ngx_resource(),
1143				m_depth_buffer.ngx_resource(),
1144				m_mvec_buffer.ngx_resource(),
1145				m_exposure_buffer.ngx_resource(),
1146				m_output_buffer.ngx_resource()
1147			);
1148		}
1149	
1150		cudaSurfaceObject_t frame() override {
1151			return m_frame_buffer.surface();
1152		}
1153	
1154		cudaSurfaceObject_t depth() override {
1155			return m_depth_buffer.surface();
1156		}
1157	
1158		cudaSurfaceObject_t mvec() override {
1159			return m_mvec_buffer.surface();
1160		}
1161	
1162		cudaSurfaceObject_t exposure() override {
1163			return m_exposure_buffer.surface();
1164		}
1165	
1166		cudaSurfaceObject_t output() override {
1167			return m_output_buffer.surface();
1168		}
1169	
1170		ivec2 clamp_resolution(const ivec2& resolution) const {
1171			float min_distance = std::numeric_limits<float>::infinity();
1172			DlssFeatureSpecs min_distance_specs = {};
1173			for (const auto& specs : m_dlss_specs) {
1174				float distance = specs.distance(resolution);
1175				if (distance <= min_distance) {
1176					min_distance = distance;
1177					min_distance_specs = specs;
1178				}
1179			}
1180	
1181			return min_distance_specs.clamp_resolution(resolution);
1182		}
1183	
1184		ivec2 out_resolution() const override {
1185			return m_dlss_feature ? m_dlss_feature->out_resolution() : m_max_out_resolution;
1186		}
1187	
1188		ivec2 max_out_resolution() const override {
1189			return m_max_out_resolution;
1190		}
1191	
1192		bool is_hdr() const override {
1193			return m_dlss_feature && m_dlss_feature->is_hdr();
1194		}
1195	
1196		bool sharpen() const override {
1197			return m_dlss_feature && m_dlss_feature->sharpen();
1198		}
1199	
1200		EDlssQuality quality() const override {
1201			return m_dlss_feature ? m_dlss_feature->quality() : EDlssQuality::None;
1202		}
1203	
1204	private:
1205		std::shared_ptr<VulkanAndNgx> m_vk_and_ngx;
1206	
1207		std::unique_ptr<DlssFeature> m_dlss_feature;
1208		std::vector<DlssFeatureSpecs> m_dlss_specs;
1209	
1210		VulkanTexture m_frame_buffer;
1211		VulkanTexture m_depth_buffer;
1212		VulkanTexture m_mvec_buffer;
1213		VulkanTexture m_exposure_buffer;
1214		VulkanTexture m_output_buffer;
1215	
1216		ivec2 m_max_out_resolution;
1217	};
1218	
1219	std::unique_ptr<IDlss> VulkanAndNgx::init_dlss(const ivec2& out_resolution) {
1220		return std::make_unique<Dlss>(shared_from_this(), out_resolution);
1221	}
1222	
1223	}
