74	OpenXRHMD::Swapchain::Swapchain(XrSwapchainCreateInfo& rgba_create_info, XrSwapchainCreateInfo& depth_create_info, XrSession& session, XrInstance& m_instance) {
75		ScopeGuard cleanup_guard{[&]() { clear(); }};
76	
77		XR_CHECK_THROW(xrCreateSwapchain(session, &rgba_create_info, &handle));
78	
79		width = rgba_create_info.width;
80		height = rgba_create_info.height;
81	
82		{
83			uint32_t size;
84			XR_CHECK_THROW(xrEnumerateSwapchainImages(handle, 0, &size, nullptr));
85	
86			images_gl.resize(size, {XR_TYPE_SWAPCHAIN_IMAGE_OPENGL_KHR});
87			XR_CHECK_THROW(xrEnumerateSwapchainImages(handle, size, &size, (XrSwapchainImageBaseHeader*)images_gl.data()));
88	
89			// One framebuffer per swapchain image
90			framebuffers_gl.resize(size);
91		}
92	
93		if (depth_create_info.format != 0) {
94			XR_CHECK_THROW(xrCreateSwapchain(session, &depth_create_info, &depth_handle));
95	
96			uint32_t depth_size;
97			XR_CHECK_THROW(xrEnumerateSwapchainImages(depth_handle, 0, &depth_size, nullptr));
98	
99			depth_images_gl.resize(depth_size, {XR_TYPE_SWAPCHAIN_IMAGE_OPENGL_KHR});
100			XR_CHECK_THROW(xrEnumerateSwapchainImages(depth_handle, depth_size, &depth_size, (XrSwapchainImageBaseHeader*)depth_images_gl.data()));
101	
102			// We might have a different number of depth swapchain images as we have framebuffers,
103			// so we will need to bind an acquired depth image to the current framebuffer on the
104			// fly later on.
105		}
106	
107		glGenFramebuffers(framebuffers_gl.size(), framebuffers_gl.data());
108	
109		cleanup_guard.disarm();
110	}
