208		};
209	
210		uint32_t size;
211		xrEnumerateApiLayerProperties(0, &size, nullptr);
212		m_api_layer_properties.clear();
213		m_api_layer_properties.resize(size, {XR_TYPE_API_LAYER_PROPERTIES});
214		xrEnumerateApiLayerProperties(size, &size, m_api_layer_properties.data());
215	
216		if (m_print_api_layers) {
217			tlog::info() << fmt::format("API Layers ({}):", m_api_layer_properties.size());
218			for (auto p : m_api_layer_properties) {
219				tlog::info() << fmt::format(
220					"{} (v {}.{}.{}, {}) {}",
221					p.layerName,
222					XR_VERSION_MAJOR(p.specVersion),
223					XR_VERSION_MINOR(p.specVersion),
224					XR_VERSION_PATCH(p.specVersion),
225					p.layerVersion,
226					p.description
227				);
228				print_extension_properties(p.layerName);
229			}
230		}
231	
232		if (layers.size() != 0) {
233			for (const auto& e : layers) {
234				bool found = false;
235				for (XrApiLayerProperties layer : m_api_layer_properties) {
236					if (strcmp(e, layer.layerName) == 0) {
237						found = true;
238						break;
239					}
240				}
241	
242				if (!found) {
243					throw std::runtime_error{fmt::format("OpenXR API layer {} not found", e)};
244				}
245			}
246		}
247	
248		xrEnumerateInstanceExtensionProperties(nullptr, 0, &size, nullptr);
249		m_instance_extension_properties.clear();
250		m_instance_extension_properties.resize(size, {XR_TYPE_EXTENSION_PROPERTIES});
251		xrEnumerateInstanceExtensionProperties(nullptr, size, &size, m_instance_extension_properties.data());
252	
253		if (m_print_extensions) {
254			tlog::info() << fmt::format("Instance extensions ({}):", m_instance_extension_properties.size());
255			for (XrExtensionProperties extension : m_instance_extension_properties) {
256				tlog::info() << fmt::format("\t{} (Version {})", extension.extensionName, extension.extensionVersion);
257			}
258		}
259	
260		auto has_extension = [&](const char* e) {
261			for (XrExtensionProperties extension : m_instance_extension_properties) {
262				if (strcmp(e, extension.extensionName) == 0) {
263					return true;
264				}
265			}
266	
267			return false;
268		};
269	
270		for (const auto& e : extensions) {
271			if (!has_extension(e)) {
272				throw std::runtime_error{fmt::format("Required OpenXR extension {} not found", e)};
273			}
274		}
275	
276		auto add_extension_if_supported = [&](const char* extension) {
277			if (has_extension(extension)) {
278				extensions.emplace_back(extension);
279				return true;
280			}
281	
282			return false;
283		};
284	
285		if (add_extension_if_supported(XR_KHR_COMPOSITION_LAYER_DEPTH_EXTENSION_NAME)) {
286			m_supports_composition_layer_depth = true;
287		}
288	
289		if (add_extension_if_supported(XR_KHR_VISIBILITY_MASK_EXTENSION_NAME)) {
290			m_supports_hidden_area_mask = true;
291		}
292	
293		if (add_extension_if_supported(XR_EXT_EYE_GAZE_INTERACTION_EXTENSION_NAME)) {
294			m_supports_eye_tracking = true;
295		}
296	
297		XrInstanceCreateInfo instance_create_info = {XR_TYPE_INSTANCE_CREATE_INFO};
298		instance_create_info.applicationInfo = {};
299		strncpy(instance_create_info.applicationInfo.applicationName, "Instant Neural Graphics Primitives v" NGP_VERSION, XR_MAX_APPLICATION_NAME_SIZE);
300		instance_create_info.applicationInfo.applicationVersion = 1;
301		strncpy(instance_create_info.applicationInfo.engineName, "Instant Neural Graphics Primitives v" NGP_VERSION, XR_MAX_ENGINE_NAME_SIZE);
302		instance_create_info.applicationInfo.engineVersion = 1;
303		instance_create_info.applicationInfo.apiVersion = XR_API_VERSION_1_0;
304		instance_create_info.enabledExtensionCount = (uint32_t)extensions.size();
305		instance_create_info.enabledExtensionNames = extensions.data();
306		instance_create_info.enabledApiLayerCount = (uint32_t)layers.size();
307		instance_create_info.enabledApiLayerNames = layers.data();
308	
309		if (XR_FAILED(xrCreateInstance(&instance_create_info, &m_instance))) {
310			throw std::runtime_error{"Failed to create OpenXR instance"};
311		}
312	
313		XR_CHECK_THROW(xrGetInstanceProperties(m_instance, &m_instance_properties));
314		if (m_print_instance_properties) {
315			tlog::info() << "Instance Properties";
316			tlog::info() << fmt::format("\t        runtime name: '{}'", m_instance_properties.runtimeName);
317			const auto& v = m_instance_properties.runtimeVersion;
318			tlog::info() << fmt::format(
319				"\t     runtime version: {}.{}.{}",
320				XR_VERSION_MAJOR(v),
321				XR_VERSION_MINOR(v),
322				XR_VERSION_PATCH(v)
323			);
324		}
325	}
