345	void OpenXRHMD::init_configure_xr_views() {
346		uint32_t size;
347		XR_CHECK_THROW(xrEnumerateViewConfigurations(m_instance, m_system_id, 0, &size, nullptr));
348		std::vector<XrViewConfigurationType> view_config_types(size);
349		XR_CHECK_THROW(xrEnumerateViewConfigurations(m_instance, m_system_id, size, &size, view_config_types.data()));
350	
351		if (m_print_view_configuration_types) {
352			tlog::info() << fmt::format("View Configuration Types ({}):", view_config_types.size());
353			for (const auto& t : view_config_types) {
354				tlog::info() << fmt::format("\t{}", XrEnumStr(t));
355			}
356		}
357	
358		// view configurations we support, in descending preference
359		const std::vector<XrViewConfigurationType> preferred_view_config_types = {
360			//XR_VIEW_CONFIGURATION_TYPE_PRIMARY_QUAD_VARJO,
361			XR_VIEW_CONFIGURATION_TYPE_PRIMARY_STEREO
362		};
363	
364		bool found = false;
365		for (const auto& p : preferred_view_config_types) {
366			for (const auto& t : view_config_types) {
367				if (p == t) {
368					found = true;
369					m_view_configuration_type = t;
370				}
371			}
372		}
373	
374		if (!found) {
375			throw std::runtime_error{"Could not find a suitable OpenXR view configuration type"};
376		}
377	
378		// get view configuration properties
379		XR_CHECK_THROW(xrGetViewConfigurationProperties(m_instance, m_system_id, m_view_configuration_type, &m_view_configuration_properties));
380		if (m_print_view_configuration_properties) {
381			tlog::info() << "View Configuration Properties:";
382			tlog::info() << fmt::format("\t         Type: {}", XrEnumStr(m_view_configuration_type));
383			tlog::info() << fmt::format("\t         FOV Mutable: {}", m_view_configuration_properties.fovMutable ? "YES" : "NO");
384		}
385	
386		// enumerate view configuration views
387		XR_CHECK_THROW(xrEnumerateViewConfigurationViews(m_instance, m_system_id, m_view_configuration_type, 0, &size, nullptr));
388		m_view_configuration_views.clear();
389		m_view_configuration_views.resize(size, {XR_TYPE_VIEW_CONFIGURATION_VIEW});
390		XR_CHECK_THROW(xrEnumerateViewConfigurationViews(
391			m_instance,
392			m_system_id,
393			m_view_configuration_type,
394			size,
395			&size,
396			m_view_configuration_views.data()
397		));
398	
399		if (m_print_view_configuration_view) {
400			tlog::info() << "View Configuration Views, Width x Height x Samples";
401			for (size_t i = 0; i < m_view_configuration_views.size(); ++i) {
402				const auto& view = m_view_configuration_views[i];
403				tlog::info() << fmt::format(
404					"\tView {}\tRecommended: {}x{}x{}  Max: {}x{}x{}",
405					i,
406					view.recommendedImageRectWidth,
407					view.recommendedImageRectHeight,
408					view.recommendedSwapchainSampleCount,
409					view.maxImageRectWidth,
410					view.maxImageRectHeight,
411					view.maxSwapchainSampleCount
412				);
413			}
414		}
415	}
