417	void OpenXRHMD::init_check_for_xr_blend_mode() {
418		// enumerate environment blend modes
419		uint32_t size;
420		XR_CHECK_THROW(xrEnumerateEnvironmentBlendModes(m_instance, m_system_id, m_view_configuration_type, 0, &size, nullptr));
421		std::vector<XrEnvironmentBlendMode> supported_blend_modes(size);
422		XR_CHECK_THROW(xrEnumerateEnvironmentBlendModes(
423			m_instance,
424			m_system_id,
425			m_view_configuration_type,
426			size,
427			&size,
428			supported_blend_modes.data()
429		));
430	
431		if (supported_blend_modes.empty()) {
432			throw std::runtime_error{"No OpenXR environment blend modes found"};
433		}
434	
435		std::sort(std::begin(supported_blend_modes), std::end(supported_blend_modes));
436		if (m_print_environment_blend_modes) {
437			tlog::info() << fmt::format("Environment Blend Modes ({}):", supported_blend_modes.size());
438		}
439	
440		m_supported_environment_blend_modes.resize(supported_blend_modes.size());
441		m_supported_environment_blend_modes_imgui_string.clear();
442		for (size_t i = 0; i < supported_blend_modes.size(); ++i) {
443			if (m_print_environment_blend_modes) {
444				tlog::info() << fmt::format("\t{}", XrEnumStr(supported_blend_modes[i]));
445			}
446	
447			auto b = (EEnvironmentBlendMode)supported_blend_modes[i];
448			m_supported_environment_blend_modes[i] = b;
449	
450			auto b_str = to_string(b);
451			std::copy(std::begin(b_str), std::end(b_str), std::back_inserter(m_supported_environment_blend_modes_imgui_string));
452			m_supported_environment_blend_modes_imgui_string.emplace_back('\0');
453		}
454	
455		m_supported_environment_blend_modes_imgui_string.emplace_back('\0');
456		m_environment_blend_mode = m_supported_environment_blend_modes.front();
457	}
