459	void OpenXRHMD::init_xr_actions() {
460		// paths for left (0) and right (1) hands
461		XR_CHECK_THROW(xrStringToPath(m_instance, "/user/hand/left", &m_hand_paths[0]));
462		XR_CHECK_THROW(xrStringToPath(m_instance, "/user/hand/right", &m_hand_paths[1]));
463	
464		// create action set
465		XrActionSetCreateInfo action_set_create_info{XR_TYPE_ACTION_SET_CREATE_INFO, nullptr, "actionset", "actionset", 0};
466		XR_CHECK_THROW(xrCreateActionSet(m_instance, &action_set_create_info, &m_action_set));
467	
468		{
469			XrActionCreateInfo action_create_info{
470				XR_TYPE_ACTION_CREATE_INFO,
471				nullptr,
472				"hand_pose",
473				XR_ACTION_TYPE_POSE_INPUT,
474				(uint32_t)m_hand_paths.size(),
475				m_hand_paths.data(),
476				"Hand pose"
477			};
478			XR_CHECK_THROW(xrCreateAction(m_action_set, &action_create_info, &m_pose_action));
479		}
480	
481		{
482			XrActionCreateInfo action_create_info{
483				XR_TYPE_ACTION_CREATE_INFO,
484				nullptr,
485				"thumbstick_left",
486				XR_ACTION_TYPE_VECTOR2F_INPUT,
487				0,
488				nullptr,
489				"Left thumbstick"
490			};
491			XR_CHECK_THROW(xrCreateAction(m_action_set, &action_create_info, &m_thumbstick_actions[0]));
492		}
493	
494		{
495			XrActionCreateInfo action_create_info{
496				XR_TYPE_ACTION_CREATE_INFO,
497				nullptr,
498				"thumbstick_right",
499				XR_ACTION_TYPE_VECTOR2F_INPUT,
500				0,
501				nullptr,
502				"Right thumbstick"
503			};
504			XR_CHECK_THROW(xrCreateAction(m_action_set, &action_create_info, &m_thumbstick_actions[1]));
505		}
506	
507		{
508			XrActionCreateInfo action_create_info{
509				XR_TYPE_ACTION_CREATE_INFO,
510				nullptr,
511				"press",
512				XR_ACTION_TYPE_BOOLEAN_INPUT,
513				(uint32_t)m_hand_paths.size(),
514				m_hand_paths.data(),
515				"Press"
516			};
517			XR_CHECK_THROW(xrCreateAction(m_action_set, &action_create_info, &m_press_action));
518		}
519	
520		{
521			XrActionCreateInfo action_create_info{
522				XR_TYPE_ACTION_CREATE_INFO,
523				nullptr,
524				"grab",
525				XR_ACTION_TYPE_FLOAT_INPUT,
526				(uint32_t)m_hand_paths.size(),
527				m_hand_paths.data(),
528				"Grab"
529			};
530			XR_CHECK_THROW(xrCreateAction(m_action_set, &action_create_info, &m_grab_action));
531		}
532	
533		auto create_binding = [&](XrAction action, const std::string& binding_path_str) {
534			XrPath binding;
535			XR_CHECK_THROW(xrStringToPath(m_instance, binding_path_str.c_str(), &binding));
536			return XrActionSuggestedBinding{action, binding};
537		};
538	
539		auto suggest_bindings = [&](const std::string& interaction_profile_path_str, const std::vector<XrActionSuggestedBinding>& bindings) {
540			XrPath interaction_profile;
541			XR_CHECK_THROW(xrStringToPath(m_instance, interaction_profile_path_str.c_str(), &interaction_profile));
542			XrInteractionProfileSuggestedBinding suggested_binding{
543				XR_TYPE_INTERACTION_PROFILE_SUGGESTED_BINDING,
544				nullptr,
545				interaction_profile,
546				(uint32_t)bindings.size(),
547				bindings.data()
548			};
549			XR_CHECK_THROW(xrSuggestInteractionProfileBindings(m_instance, &suggested_binding));
550		};
551	
552		suggest_bindings("/interaction_profiles/khr/simple_controller", {
553			create_binding(m_pose_action, "/user/hand/left/input/grip/pose"),
554			create_binding(m_pose_action, "/user/hand/right/input/grip/pose"),
555		});
556	
557		auto suggest_controller_bindings = [&](const std::string& xy, const std::string& press, const std::string& grab, const std::string& squeeze, const std::string& interaction_profile_path_str) {
558			std::vector<XrActionSuggestedBinding> bindings = {
559				create_binding(m_pose_action, "/user/hand/left/input/grip/pose"),
560				create_binding(m_pose_action, "/user/hand/right/input/grip/pose"),
561				create_binding(m_thumbstick_actions[0], std::string{"/user/hand/left/input/"} + xy),
562				create_binding(m_thumbstick_actions[1], std::string{"/user/hand/right/input/"} + xy),
563				create_binding(m_press_action, std::string{"/user/hand/left/input/"} + press),
564				create_binding(m_press_action, std::string{"/user/hand/right/input/"} + press),
565				create_binding(m_grab_action, std::string{"/user/hand/left/input/"} + grab),
566				create_binding(m_grab_action, std::string{"/user/hand/right/input/"} + grab),
567			};
568	
569			if (!squeeze.empty()) {
570				bindings.emplace_back(create_binding(m_grab_action, std::string{"/user/hand/left/input/"} + squeeze));
571				bindings.emplace_back(create_binding(m_grab_action, std::string{"/user/hand/right/input/"} + squeeze));
572			}
573	
574			suggest_bindings(interaction_profile_path_str, bindings);
575		};
576	
577		suggest_controller_bindings("trackpad",   "select/click",     "trackpad/click", "",                  "/interaction_profiles/google/daydream_controller");
578		suggest_controller_bindings("trackpad",   "trackpad/click",   "trigger/click",  "squeeze/click",     "/interaction_profiles/htc/vive_controller");
579		suggest_controller_bindings("thumbstick", "thumbstick/click", "trigger/value",  "squeeze/click",     "/interaction_profiles/microsoft/motion_controller");
580		suggest_controller_bindings("trackpad",   "trackpad/click",   "trigger/click",  "",                  "/interaction_profiles/oculus/go_controller");
581		suggest_controller_bindings("thumbstick", "thumbstick/click", "trigger/value",  "squeeze/value",     "/interaction_profiles/oculus/touch_controller");
582	
583		// Valve Index force squeeze is very sensitive and can cause unwanted grabbing. Only permit trigger-grabbing for now.
584		suggest_controller_bindings("thumbstick", "thumbstick/click", "trigger/value",  ""/*squeeze/force*/, "/interaction_profiles/valve/index_controller");
585	
586		// Xbox controller (currently not functional)
587		suggest_bindings("/interaction_profiles/microsoft/xbox_controller", {
588			create_binding(m_thumbstick_actions[0], std::string{"/user/gamepad/input/thumbstick_left"}),
589			create_binding(m_thumbstick_actions[1], std::string{"/user/gamepad/input/thumbstick_right"}),
590		});
591	}
