594	void OpenXRHMD::init_open_gl(HDC hdc, HGLRC hglrc) {
595	#elif defined(XR_USE_PLATFORM_XLIB)
596	void OpenXRHMD::init_open_gl(Display* xDisplay, uint32_t visualid, GLXFBConfig glxFBConfig, GLXDrawable glxDrawable, GLXContext glxContext) {
597	#elif defined(XR_USE_PLATFORM_WAYLAND)
598	void OpenXRHMD::init_open_gl(wl_display* display) {
599	#endif
600		// GL graphics requirements
601		PFN_xrGetOpenGLGraphicsRequirementsKHR xrGetOpenGLGraphicsRequirementsKHR = nullptr;
602		XR_CHECK_THROW(xrGetInstanceProcAddr(
603			m_instance,
604			"xrGetOpenGLGraphicsRequirementsKHR",
605			reinterpret_cast<PFN_xrVoidFunction*>(&xrGetOpenGLGraphicsRequirementsKHR)
606		));
607	
608		XrGraphicsRequirementsOpenGLKHR graphics_requirements{XR_TYPE_GRAPHICS_REQUIREMENTS_OPENGL_KHR};
609		xrGetOpenGLGraphicsRequirementsKHR(m_instance, m_system_id, &graphics_requirements);
610		XrVersion min_version = graphics_requirements.minApiVersionSupported;
611		GLint major = 0;
612		GLint minor = 0;
613		glGetIntegerv(GL_MAJOR_VERSION, &major);
614		glGetIntegerv(GL_MINOR_VERSION, &minor);
615		const XrVersion have_version = XR_MAKE_VERSION(major, minor, 0);
616	
617		if (have_version < min_version) {
618			tlog::info() << fmt::format(
619				"Required OpenGL version: {}.{}, found OpenGL version: {}.{}",
620				XR_VERSION_MAJOR(min_version),
621				XR_VERSION_MINOR(min_version),
622				major,
623				minor
624			);
625	
626			throw std::runtime_error{"Insufficient graphics API support"};
627		}
628	
629	#if defined(XR_USE_PLATFORM_WIN32)
630		m_graphics_binding.hDC = hdc;
631		m_graphics_binding.hGLRC = hglrc;
632	#elif defined(XR_USE_PLATFORM_XLIB)
633		m_graphics_binding.xDisplay = xDisplay;
634		m_graphics_binding.visualid = visualid;
635		m_graphics_binding.glxFBConfig = glxFBConfig;
636		m_graphics_binding.glxDrawable = glxDrawable;
637		m_graphics_binding.glxContext = glxContext;
638	#elif defined(XR_USE_PLATFORM_WAYLAND)
639		m_graphics_binding.display = display;
640	#endif
641	}
