657	void OpenXRHMD::init_xr_spaces() {
658		// reference space
659		uint32_t size;
660		XR_CHECK_THROW(xrEnumerateReferenceSpaces(m_session, 0, &size, nullptr));
661		m_reference_spaces.clear();
662		m_reference_spaces.resize(size);
663		XR_CHECK_THROW(xrEnumerateReferenceSpaces(m_session, size, &size, m_reference_spaces.data()));
664	
665		if (m_print_reference_spaces) {
666			tlog::info() << fmt::format("Reference spaces ({}):", m_reference_spaces.size());
667			for (const auto& r : m_reference_spaces) {
668				tlog::info() << fmt::format("\t{}", XrEnumStr(r));
669			}
670		}
671	
672		XrReferenceSpaceCreateInfo reference_space_create_info{XR_TYPE_REFERENCE_SPACE_CREATE_INFO};
673		reference_space_create_info.referenceSpaceType = XR_REFERENCE_SPACE_TYPE_LOCAL;
674		reference_space_create_info.poseInReferenceSpace = XrPosef{};
675		reference_space_create_info.poseInReferenceSpace.orientation.w = 1.0f;
676		XR_CHECK_THROW(xrCreateReferenceSpace(m_session, &reference_space_create_info, &m_space));
677		XR_CHECK_THROW(xrGetReferenceSpaceBoundsRect(m_session, reference_space_create_info.referenceSpaceType, &m_bounds));
678	
679		if (m_print_reference_spaces) {
680			tlog::info() << fmt::format("Using reference space {}", XrEnumStr(reference_space_create_info.referenceSpaceType));
681			tlog::info() << fmt::format("Reference space boundaries: {} x {}", m_bounds.width, m_bounds.height);
682		}
683	
684		// action space
685		XrActionSpaceCreateInfo action_space_create_info{XR_TYPE_ACTION_SPACE_CREATE_INFO};
686		action_space_create_info.action = m_pose_action;
687		action_space_create_info.poseInActionSpace.orientation.w = 1.0f;
688		action_space_create_info.subactionPath = m_hand_paths[0];
689		XR_CHECK_THROW(xrCreateActionSpace(m_session, &action_space_create_info, &m_hand_spaces[0]));
690		action_space_create_info.subactionPath = m_hand_paths[1];
691		XR_CHECK_THROW(xrCreateActionSpace(m_session, &action_space_create_info, &m_hand_spaces[1]));
692	
693		// attach action set
694		XrSessionActionSetsAttachInfo attach_info{XR_TYPE_SESSION_ACTION_SETS_ATTACH_INFO};
695		attach_info.countActionSets = 1;
696		attach_info.actionSets = &m_action_set;
697		XR_CHECK_THROW(xrAttachSessionActionSets(m_session, &attach_info));
698	}
