700	void OpenXRHMD::init_xr_swapchain_open_gl() {
701		// swap chains
702		uint32_t size;
703		XR_CHECK_THROW(xrEnumerateSwapchainFormats(m_session, 0, &size, nullptr));
704		std::vector<int64_t> swapchain_formats(size);
705		XR_CHECK_THROW(xrEnumerateSwapchainFormats(m_session, size, &size, swapchain_formats.data()));
706	
707		if (m_print_available_swapchain_formats) {
708			tlog::info() << fmt::format("Swapchain formats ({}):", swapchain_formats.size());
709			for (const auto& f : swapchain_formats) {
710				tlog::info() << fmt::format("\t{:#x}", f);
711			}
712		}
713	
714		auto find_compatible_swapchain_format = [&](const std::vector<int64_t>& candidates) {
715			for (auto format : candidates) {
716				if (std::find(std::begin(swapchain_formats), std::end(swapchain_formats), format) != std::end(swapchain_formats)) {
717					return format;
718				}
719			}
720	
721			throw std::runtime_error{"No compatible OpenXR swapchain format found"};
722		};
723	
724		m_swapchain_rgba_format = find_compatible_swapchain_format({
725			GL_SRGB8_ALPHA8,
726			GL_SRGB8,
727			GL_RGBA8,
728		});
729	
730		if (m_supports_composition_layer_depth) {
731			m_swapchain_depth_format = find_compatible_swapchain_format({
732				GL_DEPTH_COMPONENT32F,
733				GL_DEPTH_COMPONENT24,
734				GL_DEPTH_COMPONENT16,
735			});
736		}
737	
738		// tlog::info() << fmt::format("Chosen swapchain format: {:#x}", m_swapchain_rgba_format);
739		for (const auto& vcv : m_view_configuration_views) {
740			XrSwapchainCreateInfo rgba_swapchain_create_info{XR_TYPE_SWAPCHAIN_CREATE_INFO};
741			rgba_swapchain_create_info.usageFlags = XR_SWAPCHAIN_USAGE_SAMPLED_BIT | XR_SWAPCHAIN_USAGE_COLOR_ATTACHMENT_BIT;
742			rgba_swapchain_create_info.format = m_swapchain_rgba_format;
743			rgba_swapchain_create_info.sampleCount = 1;
744			rgba_swapchain_create_info.width = vcv.recommendedImageRectWidth;
745			rgba_swapchain_create_info.height = vcv.recommendedImageRectHeight;
746			rgba_swapchain_create_info.faceCount = 1;
747			rgba_swapchain_create_info.arraySize = 1;
748			rgba_swapchain_create_info.mipCount = 1;
749	
750			XrSwapchainCreateInfo depth_swapchain_create_info = rgba_swapchain_create_info;
751			depth_swapchain_create_info.usageFlags = XR_SWAPCHAIN_USAGE_SAMPLED_BIT | XR_SWAPCHAIN_USAGE_DEPTH_STENCIL_ATTACHMENT_BIT;
752			depth_swapchain_create_info.format = m_swapchain_depth_format;
753	
754			m_swapchains.emplace_back(rgba_swapchain_create_info, depth_swapchain_create_info, m_session, m_instance);
755		}
756	}
