758	void OpenXRHMD::init_open_gl_shaders() {
759		// Hidden area mask program
760		{
761			static const char* shader_vert = R"(#version 140
762				in vec2 pos;
763				uniform mat4 project;
764				void main() {
765					vec4 pos = project * vec4(pos, -1.0, 1.0);
766					pos.xyz /= pos.w;
767					pos.y *= -1.0;
768					gl_Position = pos;
769				})";
770	
771			static const char* shader_frag = R"(#version 140
772				out vec4 frag_color;
773				void main() {
774					frag_color = vec4(0.0, 0.0, 0.0, 1.0);
775				})";
776	
777			GLuint vert = glCreateShader(GL_VERTEX_SHADER);
778			glShaderSource(vert, 1, &shader_vert, NULL);
779			glCompileShader(vert);
780			check_shader(vert, "OpenXR hidden area mask vertex shader", false);
781	
782			GLuint frag = glCreateShader(GL_FRAGMENT_SHADER);
783			glShaderSource(frag, 1, &shader_frag, NULL);
784			glCompileShader(frag);
785			check_shader(frag, "OpenXR hidden area mask fragment shader", false);
786	
787			m_hidden_area_mask_program = glCreateProgram();
788			glAttachShader(m_hidden_area_mask_program, vert);
789			glAttachShader(m_hidden_area_mask_program, frag);
790			glLinkProgram(m_hidden_area_mask_program);
791			check_shader(m_hidden_area_mask_program, "OpenXR hidden area mask shader program", true);
792	
793			glDeleteShader(vert);
794			glDeleteShader(frag);
795		}
796	}
