798	void OpenXRHMD::session_state_change(XrSessionState state, EControlFlow& flow) {
799		//tlog::info() << fmt::format("New session state {}", XrEnumStr(state));
800		switch (state) {
801			case XR_SESSION_STATE_READY: {
802				XrSessionBeginInfo sessionBeginInfo {XR_TYPE_SESSION_BEGIN_INFO};
803				sessionBeginInfo.primaryViewConfigurationType = m_view_configuration_type;
804				XR_CHECK_THROW(xrBeginSession(m_session, &sessionBeginInfo));
805				break;
806			}
807			case XR_SESSION_STATE_STOPPING: {
808				XR_CHECK_THROW(xrEndSession(m_session));
809				break;
810			}
811			case XR_SESSION_STATE_EXITING: {
812				flow = EControlFlow::Quit;
813				break;
814			}
815			case XR_SESSION_STATE_LOSS_PENDING: {
816				flow = EControlFlow::Restart;
817				break;
818			}
819			default: {
820				break;
821			}
822		}
823	}
