825	OpenXRHMD::EControlFlow OpenXRHMD::poll_events() {
826		bool more = true;
827		EControlFlow flow = EControlFlow::Continue;
828		while (more) {
829			// poll events
830			XrEventDataBuffer event {XR_TYPE_EVENT_DATA_BUFFER, nullptr};
831			XrResult result = xrPollEvent(m_instance, &event);
832	
833			if (XR_FAILED(result)) {
834				tlog::error() << "xrPollEvent failed";
835			} else if (XR_SUCCESS == result) {
836				switch (event.type) {
837					case XR_TYPE_EVENT_DATA_SESSION_STATE_CHANGED: {
838						const XrEventDataSessionStateChanged& e = *reinterpret_cast<XrEventDataSessionStateChanged*>(&event);
839						//tlog::info() << "Session state change";
840						//tlog::info() << fmt::format("\t from {}\t   to {}", XrEnumStr(m_session_state), XrEnumStr(e.state));
841						//tlog::info() << fmt::format("\t session {}, time {}", fmt::ptr(e.session), e.time);
842						m_session_state = e.state;
843						session_state_change(e.state, flow);
844						break;
845					}
846	
847					case XR_TYPE_EVENT_DATA_INSTANCE_LOSS_PENDING: {
848						flow = EControlFlow::Restart;
849						break;
850					}
851	
852					case XR_TYPE_EVENT_DATA_VISIBILITY_MASK_CHANGED_KHR: {
853						m_hidden_area_masks.clear();
854						break;
855					}
856	
857					case XR_TYPE_EVENT_DATA_INTERACTION_PROFILE_CHANGED: {
858						break; // Can ignore
859					}
860	
861					default: {
862						tlog::info() << fmt::format("Unhandled event type {}", XrEnumStr(event.type));
863						break;
864					}
865				}
866			} else if (XR_EVENT_UNAVAILABLE == result) {
867				more = false;
868			}
869		}
870		return flow;
871	}
