873	__global__ void read_hidden_area_mask_kernel(const ivec2 resolution, cudaSurfaceObject_t surface, uint8_t* __restrict__ mask) {
874		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
875		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
876	
877		if (x >= resolution.x || y >= resolution.y) {
878			return;
879		}
880	
881		uint32_t idx = x + resolution.x * y;
882		surf2Dread(&mask[idx], surface, x, y);
883	}
