885	std::shared_ptr<Buffer2D<uint8_t>> OpenXRHMD::rasterize_hidden_area_mask(uint32_t view_index, const XrCompositionLayerProjectionView& view) {
886		if (!m_supports_hidden_area_mask) {
887			return {};
888		}
889	
890		PFN_xrGetVisibilityMaskKHR xrGetVisibilityMaskKHR = nullptr;
891		XR_CHECK_THROW(xrGetInstanceProcAddr(
892			m_instance,
893			"xrGetVisibilityMaskKHR",
894			reinterpret_cast<PFN_xrVoidFunction*>(&xrGetVisibilityMaskKHR)
895		));
896	
897		XrVisibilityMaskKHR visibility_mask{XR_TYPE_VISIBILITY_MASK_KHR};
898		XR_CHECK_THROW(xrGetVisibilityMaskKHR(m_session, m_view_configuration_type, view_index, XR_VISIBILITY_MASK_TYPE_HIDDEN_TRIANGLE_MESH_KHR, &visibility_mask));
899	
900		if (visibility_mask.vertexCountOutput == 0 || visibility_mask.indexCountOutput == 0) {
901			return nullptr;
902		}
903	
904		std::vector<XrVector2f> vertices(visibility_mask.vertexCountOutput);
905		std::vector<uint32_t> indices(visibility_mask.indexCountOutput);
906	
907		visibility_mask.vertices = vertices.data();
908		visibility_mask.indices = indices.data();
909	
910		visibility_mask.vertexCapacityInput = visibility_mask.vertexCountOutput;
911		visibility_mask.indexCapacityInput = visibility_mask.indexCountOutput;
912	
913		XR_CHECK_THROW(xrGetVisibilityMaskKHR(m_session, m_view_configuration_type, view_index, XR_VISIBILITY_MASK_TYPE_HIDDEN_TRIANGLE_MESH_KHR, &visibility_mask));
914	
915		CUDA_CHECK_THROW(cudaDeviceSynchronize());
916	
917		ivec2 size = {view.subImage.imageRect.extent.width, view.subImage.imageRect.extent.height};
918	
919		bool tex = glIsEnabled(GL_TEXTURE_2D);
920		bool depth = glIsEnabled(GL_DEPTH_TEST);
921		bool cull = glIsEnabled(GL_CULL_FACE);
922		GLint previous_texture_id;
923		glGetIntegerv(GL_TEXTURE_BINDING_2D, &previous_texture_id);
924	
925		if (!tex) glEnable(GL_TEXTURE_2D);
926		if (depth) glDisable(GL_DEPTH_TEST);
927		if (cull) glDisable(GL_CULL_FACE);
928	
929		// Generate texture to hold hidden area mask. Single channel, value of 1 means visible and 0 means masked away
930		ngp::GLTexture mask_texture;
931		mask_texture.resize(size, 1, true);
932		glBindTexture(GL_TEXTURE_2D, mask_texture.texture());
933		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_NEAREST);
934		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_NEAREST);
935	
936		GLuint framebuffer = 0;
937		glGenFramebuffers(1, &framebuffer);
938		glBindFramebuffer(GL_FRAMEBUFFER, framebuffer);
939		glFramebufferTexture(GL_FRAMEBUFFER, GL_COLOR_ATTACHMENT0, mask_texture.texture(), 0);
940	
941		GLenum draw_buffers[1] = {GL_COLOR_ATTACHMENT0};
942		glDrawBuffers(1, draw_buffers);
943	
944		glViewport(0, 0, size.x, size.y);
945	
946		// Draw hidden area mask
947		GLuint vao;
948		glGenVertexArrays(1, &vao);
949		glBindVertexArray(vao);
950	
951		GLuint vertex_buffer;
952		glGenBuffers(1, &vertex_buffer);
953		glEnableVertexAttribArray(0);
954		glBindBuffer(GL_ARRAY_BUFFER, vertex_buffer);
955		glBufferData(GL_ARRAY_BUFFER, sizeof(XrVector2f) * vertices.size(), vertices.data(), GL_STATIC_DRAW);
956		glVertexAttribPointer(0, 2, GL_FLOAT, GL_FALSE, 0, (void*)0);
957	
958		GLuint index_buffer;
959		glGenBuffers(1, &index_buffer);
960		glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, index_buffer);
961		glBufferData(GL_ELEMENT_ARRAY_BUFFER, sizeof(uint32_t) * indices.size(), indices.data(), GL_STATIC_DRAW);
962	
963		glClearColor(1.0f, 1.0f, 1.0f, 1.0f);
964		glClear(GL_COLOR_BUFFER_BIT);
965		glUseProgram(m_hidden_area_mask_program);
966	
967		XrMatrix4x4f proj;
968		XrMatrix4x4f_CreateProjectionFov(&proj, GRAPHICS_OPENGL, view.fov, 1.0f / 128.0f, 128.0f);
969	
970		GLuint project_id = glGetUniformLocation(m_hidden_area_mask_program, "project");
971		glUniformMatrix4fv(project_id, 1, GL_FALSE, &proj.m[0]);
972	
973		glDrawElements(GL_TRIANGLES, indices.size(), GL_UNSIGNED_INT, (void*)0);
974		glFinish();
975	
976		glDisableVertexAttribArray(0);
977		glDeleteBuffers(1, &vertex_buffer);
978		glDeleteBuffers(1, &index_buffer);
979		glDeleteVertexArrays(1, &vao);
980		glDeleteFramebuffers(1, &framebuffer);
981	
982		glBindVertexArray(0);
983		glUseProgram(0);
984	
985		// restore old state
986		if (!tex) glDisable(GL_TEXTURE_2D);
987		if (depth) glEnable(GL_DEPTH_TEST);
988		if (cull) glEnable(GL_CULL_FACE);
989		glBindTexture(GL_TEXTURE_2D, previous_texture_id);
990		glBindFramebuffer(GL_FRAMEBUFFER, 0);
991	
992		std::shared_ptr<Buffer2D<uint8_t>> mask = std::make_shared<Buffer2D<uint8_t>>(size);
993	
994		const dim3 threads = { 16, 8, 1 };
995		const dim3 blocks = { div_round_up((uint32_t)size.x, threads.x), div_round_up((uint32_t)size.y, threads.y), 1 };
996	
997		read_hidden_area_mask_kernel<<<blocks, threads>>>(size, mask_texture.surface(), mask->data());
998		CUDA_CHECK_THROW(cudaDeviceSynchronize());
999	
1000		return mask;
1001	}
